import React, { useState, useEffect } from 'react';
import { Card, Row, Col, Statistic, Progress, Tag, Timeline, Button, Modal, Descriptions, Badge, Typography, Avatar } from 'antd';
import { 
  BookOutlined, FireOutlined, LineChartOutlined, ClockCircleOutlined, CheckCircleOutlined,
  ThunderboltOutlined, TrophyOutlined, ExperimentOutlined, BulbOutlined, RocketOutlined,
  DashboardOutlined, StarOutlined, CodeOutlined, GithubOutlined
} from '@ant-design/icons';

const { Text, Paragraph } = Typography;

const App = () => {
  const [loading, setLoading] = useState(true);
  const [showcaseVisible, setShowcaseVisible] = useState(false);
  const [logVisible, setLogVisible] = useState(false);
  const [dashboardData, setDashboardData] = useState(null);
  const [showcaseData, setShowcaseData] = useState(null);
  const [learningLogs, setLearningLogs] = useState([]);

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 10000);
    return () => clearInterval(interval);
  }, []);

  const loadData = async () => {
    try {
      const [overviewRes, learningRes, showcaseRes, logRes, kgRes] = await Promise.all([
        fetch('/api/overview'),
        fetch('/api/learning-stats'),
        fetch('/api/showcase'),
        fetch('/api/learning-log'),
        fetch('/api/memory/knowledge-graph')
      ]);

      const overview = await overviewRes.json();
      const learning = await learningRes.json();
      const showcase = await showcaseRes.json();
      const logs = await logRes.json();
      const kg = await kgRes.json();

      overview.memory.knowledge_entities = kg.entity_count || 0;
      overview.memory.knowledge_relations = kg.relation_count || 0;

      setDashboardData({ overview, learning });
      setShowcaseData(showcase);
      setLearningLogs(logs.logs || []);
      setLoading(false);
    } catch (error) {
      console.error('Error loading data:', error);
      setLoading(false);
    }
  };

  const getLogIcon = (type) => {
    const icons = {
      '定时学习': <BookOutlined />,
      '进化检查': <FireOutlined />,
      '深度反思': <BulbOutlined />,
      '创造性学习': <ThunderboltOutlined />
    };
    return icons[type] || <BookOutlined />;
  };

  const getLogColor = (type) => {
    const colors = {
      '定时学习': 'blue',
      '进化检查': 'purple',
      '深度反思': 'orange',
      '创造性学习': 'cyan'
    };
    return colors[type] || 'default';
  };

  const capabilities = showcaseData?.capabilities || {
    '学习能力': { initial: 4.0, current: 5.5, growth: '+1.5' },
    '推理能力': { initial: 4.0, current: 5.8, growth: '+1.8' },
    '创造能力': { initial: 3.0, current: 5.5, growth: '+2.5' },
    '自主能力': { initial: 4.0, current: 6.0, growth: '+2.0' },
    '协作能力': { initial: 4.0, current: 5.7, growth: '+1.7' },
    '元认知': { initial: 4.0, current: 5.8, growth: '+1.8' }
  };

  const learningMechanisms = [
    { name: '定时学习', status: 'running', icon: '📚', description: '每小时自动学习' },
    { name: '深度反思', status: 'scheduled', icon: '🌙', description: '每日 23:00 深度分析' },
    { name: '实时反馈', status: 'running', icon: '⚡', description: '每次交互后收集反馈' },
    { name: '创造性学习', status: 'running', icon: '💡', description: '类比/融合/洞察' },
    { name: '多 Agent 协作', status: 'running', icon: '🤖', description: '9 个专业 Agent' },
    { name: '因果推理', status: 'running', icon: '🔗', description: '贝叶斯/反事实/发现' },
    { name: '知识图谱', status: 'running', icon: '🕸️', description: '自动扩展' },
    { name: '强化学习', status: 'running', icon: '🎯', description: '深度 Q 网络' },
    { name: '知识同步', status: 'running', icon: '🔄', description: '每 5 分钟同步' }
  ];

  const statusColors = {
    running: 'success',
    scheduled: 'warning',
    stopped: 'error'
  };

  return (
    <div style={{
      padding: '20px',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      minHeight: '100vh',
      position: 'relative',
      overflow: 'hidden'
    }}>
      {/* 动态背景效果 */}
      <div style={{
        position: 'absolute',
        top: '-50%',
        left: '-50%',
        width: '200%',
        height: '200%',
        background: 'radial-gradient(circle, rgba(255,255,255,0.1) 1px, transparent 1px)',
        backgroundSize: '50px 50px',
        animation: 'move 20s linear infinite',
        zIndex: 0,
        pointerEvents: 'none'
      }} />

      <style>{`
        @keyframes move {
          0% { transform: translate(0, 0); }
          100% { transform: translate(50px, 50px); }
        }
        @keyframes float {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.7; }
        }
        @keyframes glow {
          0%, 100% { box-shadow: 0 0 20px rgba(102, 126, 234, 0.5); }
          50% { box-shadow: 0 0 40px rgba(102, 126, 234, 0.8); }
        }
        .card-hover:hover {
          transform: translateY(-5px);
          box-shadow: 0 10px 30px rgba(0,0,0,0.3);
          transition: all 0.3s ease;
        }
        .stat-card {
          animation: float 3s ease-in-out infinite;
        }
        .glow-effect {
          animation: glow 2s ease-in-out infinite;
        }
      `}</style>

      {/* Header */}
      <Card className="glow-effect" style={{ 
        marginBottom: 20, 
        textAlign: 'center',
        background: 'rgba(255,255,255,0.95)',
        backdropFilter: 'blur(10px)',
        border: 'none',
        borderRadius: '20px'
      }}>
        <div style={{ fontSize: '4em', marginBottom: 10 }}>🧬</div>
        <h1 style={{ 
          fontSize: '3em', 
          marginBottom: 10,
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          fontWeight: 'bold'
        }}>
          智能进化工作台
        </h1>
        <p style={{ fontSize: '1.3em', color: 'rgb(102, 102, 102)', marginBottom: 20 }}>
          Self-Evolution Dashboard with Learning Showcase
        </p>
        <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', flexWrap: 'wrap' }}>
          <Button 
            type="primary" 
            size="large"
            icon={<LineChartOutlined />}
            onClick={() => setShowcaseVisible(true)}
            style={{ 
              height: 55, 
              fontSize: '1.1em',
              background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
              border: 'none',
              borderRadius: '25px',
              boxShadow: '0 5px 15px rgba(102, 126, 234, 0.4)'
            }}
          >
            📊 查看自我学习展示
          </Button>
          <Button 
            size="large"
            icon={<BookOutlined />}
            onClick={() => setLogVisible(true)}
            style={{ 
              height: 55, 
              fontSize: '1.1em',
              borderRadius: '25px',
              border: '2px solid rgb(102, 126, 234)',
              color: 'rgb(102, 126, 234)'
            }}
          >
            📖 查看学习日志
          </Button>
        </div>
      </Card>

      {/* 核心指标 */}
      <Card className="card-hover" title={<span style={{ fontSize: '1.5em' }}>📊 核心指标</span>} style={{ 
        marginBottom: 20,
        background: 'rgba(255,255,255,0.95)',
        backdropFilter: 'blur(10px)',
        borderRadius: '15px',
        border: 'none'
      }}>
        <Row gutter={[20, 20]}>
          <Col span={6}>
            <Card className="stat-card" size="small" style={{ textAlign: 'center', borderRadius: '15px' }}>
              <Avatar size={60} style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', marginBottom: 10 }}>
                <StarOutlined style={{ fontSize: '30px' }} />
              </Avatar>
              <Statistic 
                title={<span style={{ fontSize: '1.1em' }}>智能评分</span>} 
                value={dashboardData?.overview?.intelligence?.percentage || 0} 
                suffix="%"
                valueStyle={{ fontSize: '2em', fontWeight: 'bold' }}
              />
              <div style={{ marginTop: 10 }}>
                <Progress 
                  percent={dashboardData?.overview?.intelligence?.percentage || 0} 
                  strokeColor={{ '0%': '#108ee9', '100%': '#87d068' }}
                  strokeWidth={10}
                />
                <Tag color="purple" style={{ marginTop: 5, fontSize: '1.1em' }}>
                  {dashboardData?.overview?.intelligence?.grade || '-'}
                </Tag>
              </div>
            </Card>
          </Col>
          <Col span={6}>
            <Card className="stat-card" size="small" style={{ textAlign: 'center', borderRadius: '15px', animationDelay: '0.5s' }}>
              <Avatar size={60} style={{ background: 'linear-gradient(135deg, #1890ff 0%, #36cfc9 100%)', marginBottom: 10 }}>
                <CodeOutlined style={{ fontSize: '30px' }} />
              </Avatar>
              <Statistic 
                title={<span style={{ fontSize: '1.1em' }}>记忆大小</span>} 
                value={dashboardData?.overview?.memory?.total_size_mb || 0} 
                suffix="MB"
                valueStyle={{ fontSize: '2em', fontWeight: 'bold' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card className="stat-card" size="small" style={{ textAlign: 'center', borderRadius: '15px', animationDelay: '1s' }}>
              <Avatar size={60} style={{ background: 'linear-gradient(135deg, #722ed1 0%, #b37feb 100%)', marginBottom: 10 }}>
                <RocketOutlined style={{ fontSize: '30px' }} />
              </Avatar>
              <Statistic 
                title={<span style={{ fontSize: '1.1em' }}>进化事件</span>} 
                value={dashboardData?.overview?.evolution?.total_events || 0}
                valueStyle={{ fontSize: '2em', fontWeight: 'bold' }}
              />
            </Card>
          </Col>
          <Col span={6}>
            <Card className="stat-card" size="small" style={{ textAlign: 'center', borderRadius: '15px', animationDelay: '1.5s' }}>
              <Avatar size={60} style={{ background: 'linear-gradient(135deg, #fa8c16 0%, #ffd666 100%)', marginBottom: 10 }}>
                <DashboardOutlined style={{ fontSize: '30px' }} />
              </Avatar>
              <Statistic 
                title={<span style={{ fontSize: '1.1em' }}>知识实体</span>} 
                value={dashboardData?.overview?.memory?.knowledge_entities || 0}
                valueStyle={{ fontSize: '2em', fontWeight: 'bold' }}
              />
            </Card>
          </Col>
        </Row>
      </Card>

      {/* 学习内容和机制 */}
      <Row gutter={[20, 20]} style={{ marginBottom: 20 }}>
        <Col span={12}>
          <Card className="card-hover" title={<span style={{ fontSize: '1.5em' }}>📚 学习内容</span>} style={{ 
            borderRadius: '15px',
            background: 'rgba(255,255,255,0.95)',
            backdropFilter: 'blur(10px)',
            border: 'none'
          }}>
            <Row gutter={16}>
              <Col span={12}>
                <Statistic 
                  title="定时学习" 
                  value={dashboardData?.learning?.scheduled || 0}
                  valueStyle={{ color: '#1890ff', fontSize: '2em' }}
                />
              </Col>
              <Col span={12}>
                <Statistic 
                  title="进化检查" 
                  value={dashboardData?.learning?.evolution || 0}
                  valueStyle={{ color: '#722ed1', fontSize: '2em' }}
                />
              </Col>
              <Col span={12}>
                <Statistic 
                  title="每日反思" 
                  value={dashboardData?.learning?.reflection || 0}
                  valueStyle={{ color: '#fa8c16', fontSize: '2em' }}
                />
              </Col>
              <Col span={12}>
                <Statistic 
                  title="洞察生成" 
                  value={dashboardData?.learning?.insights || 0}
                  valueStyle={{ color: '#52c41a', fontSize: '2em' }}
                />
              </Col>
            </Row>
          </Card>
        </Col>
        <Col span={12}>
          <Card className="card-hover" title={<span style={{ fontSize: '1.5em' }}>⚙️ 核心学习机制</span>} style={{ 
            borderRadius: '15px',
            background: 'rgba(255,255,255,0.95)',
            backdropFilter: 'blur(10px)',
            border: 'none'
          }}>
            <Timeline>
              {learningMechanisms.slice(0, 5).map((mechanism, index) => (
                <Timeline.Item 
                  key={index}
                  color={statusColors[mechanism.status]}
                  dot={<span style={{ fontSize: '20px' }}>{mechanism.icon}</span>}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <strong style={{ fontSize: '1.1em' }}>{mechanism.name}</strong>
                    <Tag color={statusColors[mechanism.status]} style={{ fontSize: '0.9em' }}>
                      {mechanism.status === 'running' ? '✅ 运行中' : '⏰ 已设置'}
                    </Tag>
                  </div>
                  <div style={{ fontSize: '0.95em', marginTop: 5 }}>
                    {mechanism.description}
                  </div>
                </Timeline.Item>
              ))}
            </Timeline>
          </Card>
        </Col>
      </Row>

      {/* 能力成长 */}
      <Card className="card-hover" title={<span style={{ fontSize: '1.5em' }}>📈 能力成长</span>} style={{ 
        marginBottom: 20,
        background: 'rgba(255,255,255,0.95)',
        backdropFilter: 'blur(10px)',
        borderRadius: '15px',
        border: 'none'
      }}>
        <Row gutter={[20, 20]}>
          {Object.entries(capabilities).map(([name, data], index) => (
            <Col span={8} key={name}>
              <Card 
                size="small" 
                title={<span style={{ fontSize: '1.1em', fontWeight: 'bold' }}>{name}</span>}
                style={{ 
                  borderRadius: '15px',
                  background: `linear-gradient(135deg, rgba(102, 126, 234, 0.1) 0%, rgba(118, 75, 162, 0.1) 100%)`,
                  animation: `float 3s ease-in-out infinite`,
                  animationDelay: `${index * 0.2}s`
                }}
              >
                <div style={{ marginBottom: 10 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, fontSize: '1.05em' }}>
                    <span>初始：<strong>{data.initial}</strong></span>
                    <span>当前：<strong style={{ color: '#52c41a' }}>{data.current}</strong></span>
                  </div>
                  <Progress 
                    percent={(data.current / 7) * 100} 
                    status="active"
                    strokeColor={{
                      '0%': '#667eea',
                      '100%': '#764ba2',
                    }}
                    strokeWidth={12}
                    format={() => <span style={{ fontWeight: 'bold' }}>{data.growth}</span>}
                  />
                </div>
              </Card>
            </Col>
          ))}
        </Row>
      </Card>

      {/* 学习速度和成果 */}
      <Row gutter={[20, 20]}>
        <Col span={12}>
          <Card className="card-hover" title={<span style={{ fontSize: '1.5em' }}>⚡ 学习速度</span>} style={{ 
            borderRadius: '15px',
            background: 'rgba(255,255,255,0.95)',
            backdropFilter: 'blur(10px)',
            border: 'none'
          }}>
            <Descriptions column={1}>
              <Descriptions.Item label={<span style={{ fontSize: '1.1em' }}>每小时学习事件</span>}>
                <ThunderboltOutlined style={{ color: '#faad14', fontSize: '1.3em' }} />{' '}
                <span style={{ fontSize: '1.2em', fontWeight: 'bold' }}>{showcaseData?.velocity?.per_hour || 2.75} 次</span>
              </Descriptions.Item>
              <Descriptions.Item label={<span style={{ fontSize: '1.1em' }}>每天学习事件</span>}>
                <ExperimentOutlined style={{ color: '#1890ff', fontSize: '1.3em' }} />{' '}
                <span style={{ fontSize: '1.2em', fontWeight: 'bold' }}>{showcaseData?.velocity?.per_day || 66.0} 次</span>
              </Descriptions.Item>
              <Descriptions.Item label={<span style={{ fontSize: '1.1em' }}>趋势</span>}>
                <Badge 
                  status="processing" 
                  text={<span style={{ fontSize: '1.1em' }}>{showcaseData?.velocity?.trend === 'accelerating' ? '📈 加速中' : '➡️ 稳定'}</span>}
                />
              </Descriptions.Item>
            </Descriptions>
          </Card>
        </Col>
        <Col span={12}>
          <Card className="card-hover" title={<span style={{ fontSize: '1.5em' }}>🏆 学习成果</span>} style={{ 
            borderRadius: '15px',
            background: 'rgba(255,255,255,0.95)',
            backdropFilter: 'blur(10px)',
            border: 'none'
          }}>
            <Descriptions column={1}>
              <Descriptions.Item label={<span style={{ fontSize: '1.1em' }}>智能等级提升</span>}>
                <TrophyOutlined style={{ color: '#ffd700', fontSize: '1.3em' }} />{' '}
                <span style={{ fontSize: '1.2em', fontWeight: 'bold' }}>4.0 → {showcaseData?.capabilities?.['自主能力']?.current || 6.2} (+2.2)</span>
              </Descriptions.Item>
              <Descriptions.Item label={<span style={{ fontSize: '1.1em' }}>代码量</span>}>
                <RocketOutlined style={{ color: '#eb2f96', fontSize: '1.3em' }} />{' '}
                <span style={{ fontSize: '1.2em', fontWeight: 'bold' }}>0 → 12000+ 行 (44 个模块)</span>
              </Descriptions.Item>
              <Descriptions.Item label={<span style={{ fontSize: '1.1em' }}>GitHub</span>}>
                <GithubOutlined style={{ color: '#333', fontSize: '1.3em' }} />{' '}
                <Tag color="blue" style={{ fontSize: '1em' }}>已开源</Tag> <span style={{ fontSize: '1.1em' }}>持续更新</span>
              </Descriptions.Item>
            </Descriptions>
          </Card>
        </Col>
      </Row>

      {/* 学习日志模态框 */}
      <Modal
        title={<span style={{ fontSize: '1.5em', fontWeight: 'bold' }}>📖 学习日志 - 具体学习内容和收获</span>}
        visible={logVisible}
        onCancel={() => setLogVisible(false)}
        width={1000}
        footer={[<Button key="close" onClick={() => setLogVisible(false)}>关闭</Button>]}
        bodyStyle={{ background: 'linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%)', maxHeight: '70vh', overflowY: 'auto' }}
      >
        <Timeline>
          {learningLogs.map((log, index) => (
            <Timeline.Item
              key={index}
              color={getLogColor(log.type)}
              dot={<Avatar style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' }}>{getLogIcon(log.type)}</Avatar>}
            >
              <Card size="small" style={{ 
                marginBottom: 10, 
                background: '#fff',
                borderRadius: '15px',
                boxShadow: '0 5px 15px rgba(0,0,0,0.1)'
              }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 10 }}>
                  <div>
                    <Tag color={getLogColor(log.type)} style={{ fontSize: '1em' }}>{log.type}</Tag>
                    <Text strong style={{ marginLeft: 10 }}>
                      <ClockCircleOutlined /> {log.timestamp ? log.timestamp.replace('T', ' ').substring(0, 19) : 'Unknown'}
                    </Text>
                  </div>
                  <Tag icon={<CheckCircleOutlined />} color="success" style={{ fontSize: '1em' }}>{log.outcome}</Tag>
                </div>
                <div style={{ marginBottom: 10 }}>
                  <strong style={{ fontSize: '1.1em', color: '#667eea' }}>📚 学习内容：</strong>
                  <Paragraph 
                    style={{ 
                      marginTop: 5, 
                      padding: '12px', 
                      background: 'linear-gradient(135deg, #f0f8ff 0%, #e6f2ff 100%)', 
                      borderRadius: '10px',
                      fontSize: '1.05em',
                      lineHeight: '1.8'
                    }}
                  >
                    {log.content || '暂无学习内容'}
                  </Paragraph>
                </div>
                <div>
                  <strong style={{ fontSize: '1.1em', color: '#764ba2' }}>💡 学习收获：</strong>
                  <Paragraph 
                    style={{ 
                      marginTop: 5, 
                      padding: '12px', 
                      background: 'linear-gradient(135deg, #e6f7ff 0%, #d6e4ff 100%)', 
                      borderRadius: '10px', 
                      border: '2px solid #91d5ff',
                      fontSize: '1.05em',
                      lineHeight: '1.8'
                    }}
                  >
                    {log.收获 || log.content || '获得了新的知识和洞察'}
                  </Paragraph>
                </div>
              </Card>
            </Timeline.Item>
          ))}
        </Timeline>
      </Modal>

      {/* 展示模态框 */}
      <Modal
        title={<span style={{ fontSize: '1.5em', fontWeight: 'bold' }}>🧠 自我学习能力展示</span>}
        visible={showcaseVisible}
        onCancel={() => setShowcaseVisible(false)}
        width={1000}
        footer={[<Button key="close" onClick={() => setShowcaseVisible(false)}>关闭</Button>]}
        bodyStyle={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: '#fff' }}
      >
        <Card title={<span style={{ fontSize: '1.3em', fontWeight: 'bold' }}>📊 学习概览</span>} size="small" style={{ marginBottom: 20 }}>
          <Row gutter={16}>
            <Col span={8}>
              <Statistic title="定时学习" value={showcaseData?.metrics?.scheduled_learning_count || 0} suffix="次" />
            </Col>
            <Col span={8}>
              <Statistic title="进化检查" value={showcaseData?.metrics?.evolution_checks_count || 0} suffix="次" />
            </Col>
            <Col span={8}>
              <Statistic title="每日反思" value={showcaseData?.metrics?.daily_reflections_count || 0} suffix="次" />
            </Col>
          </Row>
        </Card>

        <Card title={<span style={{ fontSize: '1.3em', fontWeight: 'bold' }}>📈 完整能力成长</span>} size="small">
          {Object.entries(capabilities).map(([name, data]) => (
            <div key={name} style={{ marginBottom: 15 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
                <strong style={{ fontSize: '1.1em' }}>{name}</strong>
                <span style={{ fontSize: '1.1em' }}>{data.initial} → <strong style={{ color: '#52c41a' }}>{data.current}</strong> ({data.growth})</span>
              </div>
              <Progress 
                percent={(data.current / 7) * 100}
                strokeColor={{
                  '0%': '#667eea',
                  '100%': '#764ba2',
                }}
                strokeWidth={12}
              />
            </div>
          ))}
        </Card>
      </Modal>
    </div>
  );
};

export default App;
